"""
MKT Original Language Commentary — Isaiah chapters 29–32
Run: python3 scripts/zc-original-isaiah-29-32.py

Key decisions in this range:
- Ch 29: ʾAriʾēl (v1) = "lioness/hearth of God" — double meaning; the same city that
  performs sacrifice becomes the sacrifice; rdm (deep sleep, v10) = the word used in
  Gen 2:21 for Adam's sleep and Gen 15:12 for Abraham's visionary trance — Rom 11:8
  cites v10; 29:13 is DIRECTLY quoted by Jesus (Matt 15:8-9 / Mark 7:6-7);
  29:14 is DIRECTLY quoted by Paul (1 Cor 1:19).
- Ch 30: Rahab-who-sits-still (v7) = Egypt as useless chaos-monster; the woe to
  rebellious children (vv1-5) who bypass prophetic word for Egyptian alliance;
  30:15 ("in quietness and trust is your strength") is the faith-rest text of the OT.
- Ch 31: YHWH as both lion and hovering birds (vv4-5) — two incompatible animal
  images for divine protection; Assyria will fall by a sword not of man (v8).
- Ch 32: The righteous king (vv1-2) = Messianic anticipation; the Spirit poured from
  on high (v15) is one of the great OT Spirit-promise texts, related to Ezek 36-37,
  Joel 2, and the Pentecost fulfillment (Acts 2).
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: merge without overwriting any verse already present in existing
    # CHANGE? Do not alter the guard; concurrent agents depend on append-only behavior
    # VERIFY: run twice; second run should report identical byte count for isaiah.json
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ISAIAH = {
  "29": {
    "1": '<p><strong>hôy ʾAriʾēl ʾAriʾēl qiryat ḥānâ Dāwid</strong> = "Woe, Ariel, Ariel, the city where David camped." <em>ʾAriʾēl</em> (H740) carries a double meaning: (1) "lion of God" (<em>ʾărî</em> + <em>ʾēl</em>) — the city as a powerful beast; (2) "hearth of God" or "altar-hearth" (<em>ʾar-ʾēl</em>, cf. Ezek 43:15-16 where the altar hearth is called <em>haʾăriʾēl</em>) — Jerusalem as the city of the divine altar. The irony: the city that performs sacrifices will itself become a sacrificial hearth surrounded by siege works (v3). The double meaning is sustained throughout the oracle.</p>',
    "2": '<p><strong>waăṣartî ʿal-ʾAriʾēl wĕhāyĕtâ tĕʾăniyyâ waʾĕniyyâ</strong> = "I will press hard upon Ariel (<em>ṣûr</em>, to besiege/distress), and she will be full of lamentation (<em>tĕʾăniyyâ</em>) and moaning (<em>ʾăniyyâ</em>)." The wordplay on <em>ʾAriʾēl</em> continues: <strong>wĕhāyĕtâ lî kĕʾAriʾēl</strong> = "and she shall be to me like an Ariel" — the city becomes the thing its name signifies. The siege transforms Jerusalem into the hearth/altar of divine judgment, just as its altar was the hearth of sacrifice.</p>',
    "3": '<p><strong>wĕḥānîtî ʿālayik dûr</strong> = "I will encamp against you as a circle (<em>dûr</em>)" — the siege works surrounding Jerusalem. <strong>wĕṣartî ʿālayik māṣâb</strong> = "and I will besiege you with a siege mound (<em>māṣâb</em>)." <strong>wăhăqîmōtî ʿālayik mĕṣurōt</strong> = "and I will raise up siege towers (<em>mĕṣurōt</em>) against you." Three different siege-work terms — the vocabulary of ancient military engineering — applied to YHWH attacking his own city. The enemy, whoever it is militarily, is YHWH\'s instrument.</p>',
    "4": '<p><strong>wĕšāpalt mittĕreṣ tĕdabbērî</strong> = "you will be brought low, you will speak from the ground (<em>ʾereṣ</em>)" — humiliation described as speaking from the earth rather than upright. <strong>ûmēʿāpār tiŝpeh ʾimrātek</strong> = "and your speech (<em>ʾimrâ</em>) will come muffled from the dust." <strong>kĕʾôḇ mēʾereṣ qôlēk</strong> = "like a ghost/spirit-medium (<em>ʾôḇ</em>) from the ground, your voice" — the defeated city speaks like a necromantic spirit, a murmur from below ground. The city that pursued the dead (cf. 8:19) will speak like the dead.</p>',
    "5": '<p><strong>wĕhāyâ kĕʾāḇāq dak hămôn zārāyik</strong> = "and the multitude (<em>hāmôn</em>) of your foes will become like fine dust (<em>ʾāḇāq dak</em>)" — the sudden reversal: the siege armies that reduced Jerusalem to a whisper will themselves become dust. <strong>ûkĕmōṣ ʿōḇēr hămôn ʿārîṣîm</strong> = "and the multitude of the ruthless like blowing chaff (<em>môṣ ʿōḇēr</em>)" — the judgment works both ways: Jerusalem humbled, then enemies scattered. The eschatological double reversal.</p>',
    "6": '<p><strong>mēʿim YHWH ṣĕḇāʾôt tiPPāqēd</strong> = "from YHWH of armies she will be visited (<em>pāqad</em>)" — <em>pāqad</em> (H6485) = to visit in attention, either for blessing or judgment; here YHWH\'s visitation brings sudden reversal. <strong>bĕraʿam ûbĕraʿaš wĕqôl gādôl sûpâ ûsĕʿārâ wĕlahab ʾēš ʾōkēlâ</strong> = "with thunder, earthquake, great noise, storm, tempest, and devouring flame" — the full theophanic toolkit (cf. Exod 19:16-18; 1 Kgs 19:11-12). The reversal from siege to salvation comes through direct divine intervention in creation.</p>',
    "7": '<p><strong>wĕhāyâ kĕḥălôm ḥăzôn laylâ hămôn kol-haggôyim</strong> = "and the multitude of all the nations that fight against Ariel will be like a dream, a night vision." The dreamer wakes and the threat is gone. <strong>wĕkol-ṣōbĕhêhā ûmĕṣādôtêhā wĕhammaṣîq lāh</strong> = "all who fight against her and her fortification and those who press her hard." Three classes of attacker — all become a vanished dream at YHWH\'s intervention.</p>',
    "8": '<p><strong>wĕhāyâ kaʾăšer yaḥălōm hārāʿēḇ wĕhinnēh ʾōkēl</strong> = "as when a hungry man dreams he is eating, and awakens with his hunger unsatisfied (<em>rêqâ napšô</em>, lit. his soul is empty)." The enemy armies that dreamed of conquering Jerusalem will wake to find their campaign was illusory. The simile of the thirsty man who dreams of drinking (second image) reinforces: the apparent victory over Jerusalem will evaporate like a dream at sunrise.</p>',
    "9": '<p><strong>hitmahmĕhû wĕtĕmāhû hiššāʿăšĕʿû wĕšōʿû</strong> = "Be dull and be amazed, blind yourselves and be blind" — four imperatives of stupor, possibly ironic: Isaiah commands the people to do what they are already doing. <strong>šāḵrû wĕlōʾ yāyin nāʿû wĕlōʾ šēkār</strong> = "they are drunk but not with wine, they stagger but not with strong drink" — moral-spiritual intoxication without physical cause. The dullness is theological, not physical; it is the stupor that comes from sustained rejection of prophetic truth.</p>',
    "10": '<p><strong>kî-nāsak ʿălêkem YHWH rûaḥ tardēmâ</strong> = "For YHWH has poured out upon you a spirit of deep sleep (<em>tardēmâ</em>, H8639)." <em>Tardēmâ</em> is the word used for Adam\'s sleep (Gen 2:21) and Abraham\'s visionary trance (Gen 15:12) — a divinely induced stupor. <strong>wayĕʿaṣṣēm ʾet-ʿênêkem ʾet-hannĕḇîʾîm</strong> = "and he has closed your eyes, the prophets" — the very people whose eyes were opened for vision have their eyes shut as judgment for spurning the vision. Paul cites this verse in Rom 11:8 ("God gave them a spirit of stupor, eyes that would not see and ears that would not hear").</p>',
    "11": '<p><strong>wĕhāyâ lākem ḥăzôt hakkōl kidibĕrê hassēper heḥātûm</strong> = "And the vision of all this has become to you like the words of a sealed (<em>ḥātam</em>) scroll." The paradox: the prophetic revelation is inaccessible — either literally sealed (requiring the literate who say "I cannot read it, it is sealed," v11) or through illiteracy (v12). The word of God is present but unavailable to those in the stupor of v10.</p>',
    "12": '<p><strong>wĕnātan hassēper ʾet ʾăšer lōʾ-yādaʿ sēper</strong> = "and the scroll is given to one who cannot read (<em>lōʾ-yādaʿ sēper</em>, lit. who does not know the scroll)." The illiterate man\'s response: "I cannot read." Both classes — the literate who say "it is sealed" and the illiterate who cannot read — are equally excluded from the prophetic vision. The seal is internal (the stupor of v10), not merely external (the wax seal of v11).</p>',
    "13": '<p><strong>yaʿan kî niggaš hāʿām hazzeh bĕpîw ûbĕśĕpātāyw kibbĕdûnî ûlibbô riḥaq mimmennî</strong> = "because this people draws near with their mouth (<em>bĕpîw</em>) and honors me with their lips (<em>śĕpāhayim</em>), but their heart (<em>lēḇ</em>) is far from me." <em>Niggaš</em> = to draw near (liturgically, as in priestly approach); the form of worship is present, the substance absent.</p><p>Jesus quotes this verse in Matt 15:8-9 and Mark 7:6-7 as a direct critique of Pharisaic tradition that substitutes human precepts for the command of God. The precise Hebrew contrast (<em>bĕpîw / libbô</em> = mouth vs. heart) is the heart of Jesus\'s accusation: Corban practice honored God verbally while dishonoring parents practically. Isaiah\'s critique of empty cult becomes Jesus\'s critique of legal formalism — the structural problem is identical.</p>',
    "14": '<p><strong>lākēn hinnĕnî yôsip lĕhapliʾ ʾet-hāʿām hazzeh haplēʾ wāpele</strong> = "Therefore behold, I will again do wonderful things (<em>hiplîʾ</em>) with this people, wonderful and marvelous (<em>haplēʾ wāpele</em>)" — the divine wonder is not blessing here but judgment: the wisdom of the wise will perish. <strong>wĕʾābĕdâ ḥokmàt ḥăkāmāyw ûbînâ nĕḇōnāyw tistattār</strong> = "the wisdom (<em>ḥokmâ</em>) of its wise men will perish (<em>ʾāḇad</em>) and the understanding (<em>bînâ</em>) of its understanding men will be hidden (<em>sātar</em>)."</p><p>Paul directly quotes this verse in 1 Cor 1:19 ("I will destroy the wisdom of the wise, and the discernment of the discerning I will thwart") — applying it to the cross, which appears as foolishness to human wisdom but is the wisdom of God. The divine reversal of Isa 29:14 is enacted in the crucified Messiah: the very moment wisdom would declare the cross absurd, wisdom itself is overthrown.</p>',
    "15": '<p><strong>hôy hammaʿămîqîm meYHWH lastar ʿēṣâ</strong> = "Woe to those who hide deep (<em>māʿaq</em>) from YHWH their plan (<em>ʿēṣâ</em>)" — plotting in secret as though the hidden God cannot see. <strong>wĕhāyâ bĕmaḥšāk maʿăśêhem</strong> = "and their deeds are in the dark" — the political machinations of the Judean leadership forming unauthorized alliances (with Egypt) while claiming to serve YHWH. <strong>wayyōʾmĕrû mî rōʾênû ûmî yôdĕʿēnû</strong> = "and they say, who sees us? who knows us?" — the epistemological arrogance of those who deny divine omniscience.</p>',
    "16": '<p><strong>hăpkĕkem ʾim-kĕḥōmer hayôṣēr yeḥāšēḇ</strong> = "You turn things upside down! Shall the potter (<em>yôṣēr</em>) be regarded as the clay (<em>ḥōmer</em>)?" — the reversal of creator-creature distinction. <strong>kî-yōʾmar maʿăśeh lĕʿōśēhû lōʾ ʿāśānî</strong> = "as if the thing made (<em>maʿăśeh</em>) said of its maker (<em>ʿōśeh</em>): he did not make me." The potter/clay metaphor is the standard OT image of divine sovereignty over human creatures (cf. Jer 18; Rom 9:21). Paul cites Isa 29:16 and Isa 45:9 together in Rom 9:20-21 in his defense of God\'s sovereign election.</p>',
    "17": '<p><strong>hălôʾ-ʿôd miʿaṭ mĕʿāṭ wĕšāḇ lĕḇānôn lakkarmel</strong> = "Is it not yet a very little while until Lebanon shall be turned into a fruitful field (<em>karmel</em>)?" — the eschatological reversal: the mighty forest becomes a garden, the garden becomes wild forest. <strong>wĕhakarmel layaʿar yeḥāšēḇ</strong> = "and the fruitful field shall be regarded as a forest" — when YHWH acts, conventional categories of abundance and wilderness exchange. The vision moves from judgment (vv1-16) toward restoration (vv17-24).</p>',
    "18": '<p><strong>wĕšāmĕʿû bayyôm hahûʾ ḥĕrĕšîm diḇrê sēper</strong> = "And in that day the deaf (<em>ḥĕrĕšîm</em>) will hear the words of a scroll" — reversal of the sealed scroll (v11): what was inaccessible because of the stupor becomes accessible in the day of restoration. <strong>ûmēʾōpel ûmiḥōšek ʿênê ʿiwwĕrîm tirʾênâ</strong> = "and out of gloom and darkness the eyes of the blind will see" — the messianic signs that Jesus cited in Matt 11:5 as proof of his identity (Isa 35:5-6; Isa 42:7) are anticipated here as eschatological markers.</p>',
    "19": '<p><strong>wĕyāsĕpû ʿănāwîm bĕYHWH śimḥâ</strong> = "And the humble (<em>ʿănāwîm</em>) will increase their joy (<em>śimḥâ</em>) in YHWH." <em>ʿĂnāwîm</em> (H6041) = the poor, meek, lowly — the same word that appears in the Beatitudes context (Matt 5:5: "blessed are the meek/humble"). <strong>wĕʾebyônê ʾādām biqĕdôš yiśrāʾēl yāgîlû</strong> = "and the needy (<em>ʾebyôn</em>) among mankind will exult in the Holy One of Israel." The eschatological reversal: the humbled become the joyful.</p>',
    "20": '<p><strong>kî ʾāpes ʿārîṣ wĕkālâ lēṣ</strong> = "For the tyrant (<em>ʿārîṣ</em>) will be no more and the scoffer (<em>lēṣ</em>) will cease" — the two social enemies of the <em>ʿănāwîm</em> (the violent oppressor and the religious mocker) eliminated in the restoration. <strong>wĕnikrĕtû kol-šōqĕdê ʾāwen</strong> = "and all who watch for (<em>šāqad</em>) iniquity will be cut off" — the third category: the legalistic inquisitors who scrutinize others for violations they can exploit.</p>',
    "21": '<p><strong>maḥăṭîʾê ʾādām bĕdāḇār</strong> = "those who cause a person to sin by a word (<em>dāḇār</em>)" — litigation tactics that trap people in verbal admission. <strong>ûlĕmôkîaḥ baššaʿar yĕqōšûn</strong> = "and who lay a snare for the one who reproves at the gate" — the gate (<em>šaʿar</em>) was the public legal forum where elders held court; targeting the judge/reprover there was a perversion of justice. <strong>wayyaṭṭû bĕtōhû ṣaddîq</strong> = "and by empty argument (<em>tōhû</em>) they turn aside the righteous" — <em>tōhû</em> = chaos/emptiness/nothingness; using insubstantial legal arguments to corrupt just decisions.</p>',
    "22": '<p><strong>lākēn kōh-ʾāmar YHWH ʾel-bêt yaʿăqōb</strong> = "Therefore thus says YHWH to the house of Jacob" — the oracle of assurance that follows the reversal descriptions (vv17-21). <strong>ʾăšer pādâ ʾet-ʾAḇrāhām</strong> = "who redeemed (<em>pādâ</em>) Abraham" — an unusual application: Abraham as the one YHWH redeemed, usually applied to the Exodus. The connection of Abraham to redemption may relate to the Akedah (Gen 22) or to God\'s deliverance of Abraham from Ur. The point: the God who redeemed the father will restore the children. <strong>lōʾ-ʿattâ yēḇôš yaʿăqōb wĕlōʾ-ʿattâ pānāyw yeḥěwwārû</strong> = "Jacob shall not now be ashamed, nor shall his face now grow pale."</p>',
    "23": '<p><strong>kî bĕrĕʾôtô yĕlādāyw maʿăśēh yādāy bĕqirbô yaqĕdîšû šĕmî</strong> = "For when he sees his children, the work of my hands, in his midst, they will sanctify (<em>qiddaš</em>) my name." <em>Qiddaš</em> (piel) = to treat as holy, to recognize and declare holiness. <strong>wĕhiqdîšû ʾet-qĕdôš yaʿăqōb wĕʾet-ʾĕlōhê yiśrāʾēl yaʿărîṣû</strong> = "and they will sanctify the Holy One of Jacob and will stand in awe of (<em>ʿāraṣ</em>) the God of Israel" — the eschatological goal of divine redemption: a community that recognizes and declares the holiness of God.</p>',
    "24": '<p><strong>wĕyādĕʿû tōʿê-rûaḥ bînâ</strong> = "and those who err in spirit (<em>tōʿê-rûaḥ</em>) will come to understanding (<em>bînâ</em>)" — the restoration of the <em>bînâ</em> that was hidden (v14). <strong>wĕrōgĕnîm yilmĕdû lĕqāḥ</strong> = "and those who murmur (<em>rāgan</em>) will accept instruction (<em>lāqaḥ</em>)." <em>Rāgan</em> = to murmur, grumble against authority (used of Israel in the wilderness; cf. Num 14:2; Ps 106:25); the murmurers who rejected prophetic instruction will receive it in the day of restoration. The spiritual inversion is complete: stupor → understanding; grumbling → instruction.</p>'
  },
  "30": {
    "1": '<p><strong>hôy bānîm sôrĕrîm</strong> = "Woe, rebellious children (<em>sôrĕrîm</em>)" — <em>sārar</em> (H5637) = to be stubborn, rebellious, the root of the "stubborn and rebellious son" of Deut 21:18-21. <strong>neʾum YHWH laʿăśôt ʿēṣâ wĕlōʾ minnî</strong> = "declares YHWH, to carry out a plan but not from me" — the sin: independent policy-making that bypasses prophetic consultation of YHWH. <strong>wĕlinsōk massēkâ wĕlōʾ rûḥî</strong> = "and to make an alliance (<em>massēkâ</em>, lit. a libation/poured treaty) but not of my Spirit." The covenant negotiation with Egypt bypasses YHWH\'s Spirit who speaks through prophets.</p>',
    "2": '<p><strong>hallĕkîm lāredet miṣrayim</strong> = "who set out to go down to Egypt" — <em>yārad</em> (to go down) is the standard direction for Egypt in Hebrew geography; "going down" to Egypt reverses the Exodus\'s "coming up." <strong>ûpî lōʾ šāʾālû</strong> = "and who did not ask my mouth (<em>peh</em>)" — the prophetic oracle was the legitimate means of determining YHWH\'s will; bypassing it means bypassing YHWH himself. <strong>laʿōz bĕmaʿôz parʿōh ûlaḥăsôt bĕṣel miṣrayim</strong> = "to seek refuge in Pharaoh\'s protection and shelter in Egypt\'s shadow" — <em>ṣel</em> (shadow) is an ironic image: Egypt\'s "shadow" provides no real shade, just an illusion of protection.</p>',
    "3": '<p><strong>wĕhāyâ lākem maʿôz parʿōh lĕḇōšet</strong> = "and Pharaoh\'s protection (<em>maʿôz</em>) will become for you shame (<em>bōšet</em>)." The very thing sought for security becomes the occasion of disgrace. <strong>wĕhaḥăsûtyâ bĕṣel miṣrayim liklimmâ</strong> = "and the shelter (<em>ḥāsâ</em>) of Egypt\'s shadow will become humiliation (<em>kĕlimmâ</em>)." Both security words — <em>maʿôz</em> (stronghold) and <em>ḥāsâ</em> (shelter) — reverse to their opposites: shame and humiliation.</p>',
    "4": '<p><strong>kî-hāyû bĕZôʿan śārāyw</strong> = "For his officials are at Zoan (<em>Ṣoʿan</em>)" — Tanis, a major Egyptian delta city, the meeting place of the Egyptian court. <strong>wĕmalʾākāyw ḥānēs yagîʿû</strong> = "and his envoys reach Hanes" — another Egyptian city (possibly Heracleopolis); the diplomatic mission has traveled deep into Egypt. The verse describes the actual journey the Judean envoys have taken — Isaiah is not speaking abstractly but about a real diplomatic mission underway.</p>',
    "5": '<p><strong>kōl hikĕlîm ʿal-ʿam lōʾ yôʿîlû lāhem</strong> = "Everyone will be put to shame because of a people that cannot profit them (<em>yāʿal</em>)" — Egypt will not benefit Judah at all. <strong>lōʾ lĕʿezrâ wĕlōʾ lĕhôʿîl kî lĕḇōšet wĕgam lĕḥerpâ</strong> = "not for help and not for profit, but for shame and also for disgrace (<em>ḥerpâ</em>)." The oracle is categorical: no benefit whatsoever, only dishonor. <em>ḥerpâ</em> = the shame that comes from a failed partnership, worse than having sought no help at all.</p>',
    "6": '<p><strong>maśśāʾ bahămôt negeḇ</strong> = "The oracle (<em>maśśāʾ</em>) concerning the beasts of the Negeb" — the oracle describes the caravan route through the Negeb wilderness to Egypt. <strong>bĕʾereṣ ṣārâ wĕṣûqâ lābiʾ ûlayiš mēhem ʾepʿeh ûśārāp mĕʿôpēp</strong> = "through the land of trouble and anguish, of lioness and lion, of viper and flying serpent (<em>śārāp mĕʿôpēp</em>)" — the wilderness through which the treasure-laden caravan travels is dangerous (cf. Isa 6:2 <em>śārāp</em> = the burning serpent-beings). <strong>yiśśĕʾû ʿal-ketep ʿayirim ḥêlām</strong> = "they carry their wealth on donkeys\' backs" — the gifts for Egypt, the bribe for military protection. Going to enormous effort and expense for an alliance that will be worthless (v5).</p>',
    "7": '<p><strong>wĕmiṣrayim hebel wĕrîq yaʿzōrû</strong> = "Egypt\'s help is worthless (<em>hebel</em>) and empty (<em>rîq</em>)" — <em>hebel</em> is Qohelet\'s word for vanity/vapor; here applied to Egyptian military reliability. <strong>lākēn qārāʾtî lāzōʾt Rahab hēm šāḇet</strong> = "therefore I have called this: Rahab who sits still." <em>Rahab</em> (H7294) = the chaos-sea-monster of OT mythology (cf. Job 9:13; 26:12; Ps 87:4; 89:10), also used as a symbolic name for Egypt. "Rahab who sits still" = the chaos-beast that does nothing — a powerless monster, all reputation and no action. The ironic title deflates Egypt\'s pretension.</p>',
    "8": '<p><strong>ʿattâ bôʾ kĕtāḇāh ʿal-lûaḥ ʾittām wĕʿal-sēper ḥuqqĕhā</strong> = "Now go, write it before them on a tablet (<em>lûaḥ</em>) and inscribe it in a scroll (<em>sēper</em>)" — the act of writing preserves the prophecy for future vindication. <strong>wĕtihî lĕyôm ʾaḥărôn lĕʿad ʿad-ʿôlām</strong> = "that it may be for a later day a witness forever" — the prophecy is sealed into permanence (cf. 8:16). When Egypt proves useless and the Assyrian crisis comes, the written testimony will vindicate the prophet. The physical act of writing is the prophetic claim to predictive revelation.</p>',
    "9": '<p><strong>kî ʿam mĕrî hû bānîm kĕḥāšîm</strong> = "For they are a rebellious people (<em>mĕrî</em>), lying children (<em>kĕḥāšîm</em>)" — <em>mĕrî</em> = rebellion (the noun from the same root as Miriam and Meribah); <em>kĕḥāšîm</em> = those who deal falsely (<em>kāḥaš</em> = to lie/deny). <strong>bānîm lōʾ-ʾāḇû šĕmôaʿ tôrat YHWH</strong> = "children who were not willing to hear (<em>šāmaʿ</em>) the <em>tôrâ</em> of YHWH." The diagnosis: the Egyptian alliance is not merely a political miscalculation but a symptom of refusing prophetic instruction.</p>',
    "10": '<p><strong>ʾăšer ʾāmĕrû lārōʾîm lōʾ tirʾû</strong> = "who say to the seers (<em>rōʾîm</em>): Do not see!" — the demand to suppress prophetic vision. <strong>wĕlannĕḇîʾîm lōʾ tihzû-lānû nĕkōḥôt</strong> = "and to the prophets: Do not prophesy to us what is right (<em>nĕkōḥôt</em>)!" <strong>daḇĕrû-lānû ḥălāqôt</strong> = "speak to us smooth things (<em>ḥălāqôt</em>)" — flattering, comfortable words rather than true words. <strong>ḥězû mĕhaTtāʾôt</strong> = "prophesy illusions (<em>mĕhaTtāʾôt</em>)" — the demand for comfortable falsehood. 2 Tim 4:3 echoes this: "the time is coming when people will not endure sound teaching, but having itching ears they will accumulate for themselves teachers to suit their own passions."</p>',
    "11": '<p><strong>sûrû min-hadderek haTTû min-haʾōraḥ</strong> = "turn aside from the way, leave the path (<em>ʾōraḥ</em>)" — the demand to abandon the prophetic way entirely. <strong>haššibû mippānênû ʾet qĕdôš yiśrāʾēl</strong> = "remove from our presence the Holy One of Israel" — the most extreme demand: banish YHWH\'s presence from prophetic encounter. The "Holy One of Israel" is Isaiah\'s signature divine title (from the throne vision of ch6); to reject the prophet\'s message is to reject YHWH\'s holiness.</p>',
    "12": '<p><strong>lākēn kōh-ʾāmar qĕdôš yiśrāʾēl</strong> = "Therefore thus says the Holy One of Israel" — the rejection of the title (v11) is answered by YHWH speaking with that very title. <strong>yaʿan miʾāsĕkem baḏḏāḇār hazzeh</strong> = "because you have despised (<em>māʾas</em>) this word" — the word <em>māʾas</em> (to despise, reject) is the key accusation; rejecting the prophetic word = rejecting YHWH. <strong>wattibṭĕḥû bĕʿōšeq ûlĕzût</strong> = "and you have trusted in oppression and deceit (<em>lĕzût</em>)" — the Egyptian alliance is characterized not just as politically unwise but as morally corrupt: built on oppression and crookedness.</p>',
    "13": '<p><strong>lākēn yihyeh lākem heʿāwōn hazzeh kĕpereṣ nōpēl</strong> = "Therefore this iniquity will be to you like a bulging wall, broken and falling" — the metaphor of structural failure: <em>pereṣ nōpēl</em> = a breach/crack that leads to collapse. <strong>nibzĕqet bĕḥômat gāḇohâ</strong> = "a bulge in a high wall" — the crack in a high wall that gives suddenly without warning. <strong>ʾăšer pitʾōm lĕpetaʿ yāḇôʾ šibbĕrāh</strong> = "whose shattering (<em>šāḇar</em>) comes suddenly, in an instant (<em>petaʿ</em>)" — no warning, no gradual weakening visible; the collapse is sudden. The iniquity that appeared stable (the Egyptian alliance) will shatter catastrophically.</p>',
    "14": '<p><strong>ûšĕḇārāh kĕšeḇer nĕḇel yôṣĕrîm kātût</strong> = "and its breaking (<em>šiḇrāh</em>) will be like the breaking of a potter\'s vessel (<em>kĕlî yôṣĕr</em>) smashed ruthlessly (<em>kātût</em>)" — the metaphor shifts from structural (wall) to ceramic (pot): irreparable destruction. <strong>wĕlōʾ-yimmāṣēʾ ḇĕmitṣāṭāyw ḥereś</strong> = "and among its fragments (<em>ḥereś</em>) not a shard is found" — the breaking is so complete that not even a piece large enough to carry coals or scoop water remains. Total uselessness: the alliance that was sought for survival becomes an unredeemable wreck.</p>',
    "15": '<p><strong>kî-kōh ʾāmar ʾădōnāy YHWH qĕdôš yiśrāʾēl bĕšûḇâ wānāḥat tiwwāšēʿûn</strong> = "For thus says the Lord YHWH, the Holy One of Israel: In returning (<em>šûḇâ</em>) and rest (<em>naḥat</em>) you will be saved." <em>Šûḇâ</em> = repentance/return; <em>naḥat</em> = rest, settling/quietness. The paired terms are the spiritual equivalent of the military-political alliance they sought: instead of Egyptian cavalry, trust in YHWH\'s quiet provision. <strong>bĕhašqēṭ ûḇeḇiṭḥâ tihyeh gĕḇûratkĕm</strong> = "in quietness (<em>hašqēṭ</em>) and in trust (<em>biṭḥâ</em>) is your strength (<em>gĕḇûrâ</em>)" — the counter-intuitive logic of prophetic faith: the military strength (<em>gĕḇûrâ</em>) they sought through Egyptian cavalry is available through divine trust. <strong>wĕlōʾ ʾăḇîtem</strong> = "but you were not willing (<em>ʾābâ</em>)" — the volitional refusal.</p>',
    "16": '<p><strong>wattōʾmĕrû lōʾ kî-ʿal-sûs nānûs</strong> = "and you said: No! for we will flee on horses" — the ironic response: they seek military mobility (horses = cavalry, speed = strategic advantage) rather than divine rest. <strong>ʿal-kēn tānûsûn</strong> = "therefore you will flee" — the wordplay: they will flee (<em>nûs</em>) on horses from the enemy, not toward victory. <strong>wĕʿal-qal nirkaḇ</strong> = "and we will ride swift (<em>qal</em>) horses" — <em>qal</em> = swift, light (the word of Gen 1:2 for "over the face of the waters"). <strong>ʿal-kēn yiqallû rōdĕpêkem</strong> = "therefore your pursuers will be swift" — the speed they sought in horses will be outdone by the speed of enemies pursuing them.</p>',
    "17": '<p><strong>ʾelep miPPĕnê gaʿărat ʾeḥād</strong> = "a thousand before the rebuke (<em>gaʿărâ</em>) of one" — one enemy warrior\'s battle-cry will rout a thousand Judeans. <strong>miPPĕnê gaʿărat ḥămišşâ tānûsû</strong> = "before the rebuke of five, all of you will flee" — the expected ratio reverses: instead of one Israelite chasing a thousand (Deut 32:30; Lev 26:8), the equation flips. <strong>ʿad ʾim-nôtartem kĕtōren ʿal-rōʾš hāhār</strong> = "until you are left like a flagstaff (<em>tōren</em>) on a mountaintop" — the isolated, single flagpole on a hilltop: alone, exposed, conspicuous. The remnant reduced to a solitary marker.</p>',
    "18": '<p><strong>wĕlākēn yaḥakkeh YHWH laḥankĕkem wĕlākēn yārûm lĕraḥămĕkem</strong> = "Therefore YHWH waits (<em>ḥāḵâ</em>) to be gracious to you (<em>ḥānan</em>), and therefore he exalts himself to show you mercy (<em>raḥam</em>)." The "therefore" is unexpected after the judgment oracles of vv15-17 — but this is YHWH\'s character even in judgment: he waits, ready to be gracious. <strong>kî ʾĕlōhê mišpāṭ YHWH ʾašrê kol-ḥôkê lô</strong> = "for YHWH is a God of justice (<em>mišpāṭ</em>); blessed (<em>ʾašrê</em>) are all who wait for him." The Beatitude-form (<em>ʾašrê</em> = blessed, the OT equivalent of NT <em>makários</em>) applied to those who wait for YHWH — the spiritual posture of 8:17.</p>',
    "19": '<p><strong>kî-ʿam bĕṣiyyôn yēšēḇ bîrûšālāim</strong> = "for the people in Zion who dwell in Jerusalem" — the address shifts to a restored community. <strong>bākô lōʾ-tiḇkeh ḥānnôn yāḥannekā lĕqôl zaʿăqekā</strong> = "you will weep no more; he will surely be gracious to you at the sound of your cry (<em>zaʿăqā</em>)." <em>Ḥānan</em> (to be gracious) appears twice in one verse in the emphatic infinitive absolute construction (<em>ḥānnôn yāḥannekā</em>). The certainty of divine grace is reinforced by the grammar: "he will be-gracious-indeed gracious to you." <strong>kĕšomĕʿô ʾēleykā ʿānākā</strong> = "as soon as he hears it, he will answer you."</p>',
    "20": '<p><strong>wĕnātan lākem ʾădōnāy lehem ṣar ûmayim lāḥaṣ</strong> = "And the Lord will give you the bread of adversity (<em>ṣar</em>) and the water of affliction (<em>lāḥaṣ</em>)" — even in the coming hardship, YHWH provides. <strong>wĕlōʾ-yikkānēp ʿôd môrêkā</strong> = "and your Teacher (<em>môreh</em>) will no longer hide himself (<em>kānaṗ</em>)" — the Teacher who was hidden (cf. 8:17: hiding his face) will be revealed. <strong>wĕhāyû ʿênêkā rōʾôt ʾet-môrêkā</strong> = "and your eyes will see your Teacher." The restoration of prophetic vision: the sealed scroll (29:11) reopened, the Teacher visible.</p>',
    "21": '<p><strong>wĕʾoznêkā tišmaʿnâ dāḇār mēʾaḥărêkā lēʾmōr</strong> = "and your ears will hear a word from behind you saying" — the prophetic voice returning from behind, like a guide directing the traveler. <strong>zeh hadderek lĕkû-ḇô</strong> = "this is the way, walk in it." The restoration of prophetic direction: the people who demanded "speak smooth things" (30:10) will finally receive and follow true guidance. <strong>kî taʾămînû wĕkî taśmĕʾîlû</strong> = "when you turn to the right or when you turn to the left" — comprehensive direction for life, not just crisis moments.</p>',
    "22": '<p><strong>wĕṭimmēʾtem ʾet-ṣippûy pĕsîlê kaspekā</strong> = "and you will defile (<em>ṭāmēʾ</em>) the silver overlay (<em>ṣippûy</em>) of your graven images." <em>Ṭāmēʾ</em> (to declare unclean) applied by choice to idols: the restored community will voluntarily defile their own idols — declaring them as unclean as a corpse. <strong>wĕʾet-ʾăpuddâ massēkāt zāhābekā</strong> = "and the gold plating of your cast images" — the costly metal idols are defiled. <strong>tizrēm kĕmô dāwâ ṣēʾ tōmar lô</strong> = "you will scatter them like a menstrual cloth (<em>dāwâ</em>), saying to them: Out!" — the most powerful image of revulsion: the idols reduced to a used sanitary rag. The reformed covenant people\'s total rejection of idolatry.</p>',
    "23": '<p><strong>wĕnātan mĕṭar zarʿekā ʾăšer tizraʿ ʾet-hāʾădāmâ</strong> = "and he will give rain for the seed (<em>zereʿ</em>) with which you sow the ground" — the covenant blessings of Deuteronomy restored: rain, abundant harvest, fat pastureland. <strong>wĕlāḥem tĕḇûʾat hāʾădāmâ wĕhāyâ dāšēn wĕšāmēn</strong> = "and the bread of the produce of the ground will be rich and plentiful (<em>šāmēn</em>)" — the land gives back to Israel what it withheld in judgment (cf. 5:10: the vineyard yielding almost nothing).</p>',
    "24": '<p><strong>wĕhāʾĕlāpîm wĕhaʿăyārîm ʿōbĕdê hāʾădāmâ</strong> = "and the oxen and donkeys that work the soil" — working animals fed well on the threshed feed of restoration. <strong>bĕlîl ḥāmîṣ yōʾkēlû</strong> = "will eat salted/seasoned feed (<em>bĕlîl ḥāmîṣ</em>)" — the best feed for animals. Restoration extends to the humblest element of the agricultural economy: the well-fed working animal is the sign of a well-functioning covenant land.</p>',
    "25": '<p><strong>wĕhāyâ ʿal-kol-har-gāḇohah ûʿal-kol-gibʿâ nĕśuʾâ pĕlāgîm yĕʿārôt mayim</strong> = "and on every high mountain and every exalted hill there will be streams of water." The inversion of the wilderness curse: bare heights that had no water (cf. 41:18) will flow with streams. The image is of a thoroughly watered, abundantly productive landscape — a reversal of the drought-judgment. <strong>bĕyôm hereḡ rāḇ bĕnepol migdālôt</strong> = "on the day of great slaughter, when towers fall" — this abundance follows a great military judgment; the restoration comes through and after the decisive defeat of the enemy.</p>',
    "26": '<p><strong>wĕhāyâ ʾôr hallĕḇānâ kĕʾôr haḥammâ</strong> = "and the light (<em>ʾôr</em>) of the moon (<em>lĕḇānâ</em>) will be like the light of the sun (<em>ḥammâ</em>)" — the eschatological intensification of creation\'s light: lunar light (secondary) equals what was solar (primary). <strong>wĕʾôr haḥammâ yihyeh šiḇʿātayim kĕʾôr šiḇʿat hayyāmîm</strong> = "and the light of the sun will be sevenfold, like the light of seven days." The new creation\'s luminosity exceeds all prior calculation — light multiplied beyond its present capacity. Cf. Rev 21:23-25 where the new Jerusalem needs no sun or moon because God\'s glory illuminates it.</p>',
    "27": '<p><strong>hinnēh šēm YHWH bāʾ mimmerhāq</strong> = "Behold, the Name (<em>šēm</em>) of YHWH comes from afar" — a theophany in which YHWH\'s character and presence (his <em>šēm</em> = Name = all that he is) approaches from a distance. <strong>bōʿēr ʾappô wĕkaḇĕd maśśāʾâ</strong> = "his anger (<em>ʾap</em>) burning and heavy is the burden (<em>maśśāʾ</em>)" — the theophany is not peaceful but judicial. <strong>śĕpātāyw māleʾû zaʿam wĕlĕšônô kĕʾēš ʾōkelet</strong> = "his lips are full of indignation (<em>zaʿam</em>) and his tongue is like a consuming fire (<em>ʾēš ʾōkelet</em>)" — the divine word as fire, consuming the enemy.</p>',
    "28": '<p><strong>wĕrûḥô kĕnaḥal šôṭēp ʿad-ṣawwāʾr yaḥeṣeh</strong> = "and his breath (<em>rûaḥ</em>) is like an overflowing stream (<em>naḥal šôṭēp</em>) that reaches up to the neck" — the same flood imagery as 8:8 (the Assyrian reaching Judah\'s neck), now applied to YHWH\'s own breath/Spirit against Assyria. <strong>lāhānîp gôyim bĕnapâ šāwĕʾ</strong> = "to sift the nations with the sieve (<em>nāpâ</em>) of emptiness (<em>šāwĕʾ</em>)" — YHWH\'s breath as the refiner\'s sieve. <strong>wĕresen maṭʿeh ʿal lĕḥêy ʿammîm</strong> = "and a bridle that leads astray upon the jaws (<em>lĕḥî</em>) of the peoples" — YHWH bridles the nations as a rider bridles a horse, directing them to destruction.</p>',
    "29": '<p><strong>haššîr yihyeh lākem kĕlêl hithaqqdĕšû-ḥāg</strong> = "The song will be for you as in the night when a feast is hallowed (<em>hitqaddaš</em>)" — the worship of the night before a sacred festival, probably Passover. <strong>wĕśimḥat lēḇāḇ kĕhôlēk bĕḥālîl</strong> = "and gladness of heart like one who marches with a flute (<em>ḥālîl</em>)" — the processional music of pilgrimage. <strong>lāḇôʾ bĕhar YHWH ʾel-ṣûr yiśrāʾēl</strong> = "to go to the mountain of YHWH, to the Rock (<em>ṣûr</em>) of Israel." In the midst of the judgment-oracle, this verse inserts a liturgical note of joy: the divine judgment of Assyria will be celebrated with the same joy as a Passover night.</p>',
    "30": '<p><strong>wĕhišmîaʿ YHWH ʾet-qôl hadāratô</strong> = "and YHWH will cause the majestic voice (<em>qôl hadāratô</em>) to be heard" — the theophanic voice that judges. <strong>wĕnāḥat zĕrôʿô yirʾeh bĕzaʿam ʾap wĕlahab ʾēš ʾōkēlâ</strong> = "and the descent of his arm will be seen with furious anger (<em>zaʿam</em>), with devouring flame (<em>lahab ʾēš ʾōkēlâ</em>)" — the divine arm descending = direct intervention in battle. <strong>nepheṣ wāzerem ûʾeḇen bārād</strong> = "with cloudburst (<em>zerem</em>) and rainstorm and stones of hail" — the full arsenal of theophanic storm-weapons (cf. Josh 10:11 where YHWH fights with hailstones).</p>',
    "31": '<p><strong>kî miqPĕnê YHWH yêḥat ʾAššûr</strong> = "For Assyria will be terrified (<em>yêḥat</em>, niphal of <em>ḥātat</em>) before the voice of YHWH" — the world empire that reduced nations to nothing is itself shattered by YHWH\'s voice alone. <strong>baššēḇeṭ yakkeh</strong> = "with a rod (<em>šēḇeṭ</em>) he will strike" — cf. 10:5 where Assyria was itself called YHWH\'s rod (<em>šēḇeṭ</em>); now YHWH\'s rod strikes the rod. The instrument of judgment is itself judged.</p>',
    "32": '<p><strong>wĕhāyâ kol-maʿăḇar matteh hāmûsādâ</strong> = "and every stroke of the appointed staff" — <em>mûsādâ</em> = the staff of the appointed judgment, the Assyrian rod now redirected. <strong>wĕheyniîaḥ YHWH ʿālāyw bĕtupîm ûḇĕkinnōrôt</strong> = "YHWH will cause it to fall on them with tambourines and lyres" — the defeat of Assyria will be accompanied by worship music. <strong>ûḇĕmilḥamôt tĕnûpâ nilḥam bāh</strong> = "and in battles of shaking he will fight against them" — YHWH personally fighting against Assyria.</p>',
    "33": '<p><strong>kî-ʿārûk mēʾetemôl Topteh</strong> = "For Topheth has long been prepared" — <em>Tōpet</em> = the altar of Molech in the Valley of Hinnom (Gehenna), where children were burned as offerings (Jer 7:31-32). Here Isaiah uses Topheth as a metaphor for the burning judgment prepared for the king of Assyria. <strong>gam-hûʾ lammelek hûkān</strong> = "even for the king it has been prepared." <strong>heʿĕmîq hirḥîḇ mĕdûrātāh ʾēš wĕʿēṣîm harbenû</strong> = "he has made the pyre deep and wide, with fire and wood in abundance" — the funeral pyre is outsized: for the most powerful king on earth, YHWH prepares a correspondingly massive burning. <strong>nišmat YHWH kĕnaḥal goprit bōʿărâ bāh</strong> = "and the breath (<em>nišmat</em>) of YHWH kindles it like a stream of burning sulfur (<em>goprit</em>)" — God\'s breath (the same word as Gen 2:7 where YHWH breathes life into Adam) now breathes death into Assyria\'s king. Topheth/Gehenna as eternal judgment appears in NT as the term Jesus uses for final destruction (Matt 5:22; Mark 9:43-48).</p>'
  },
  "31": {
    "1": '<p><strong>hôy hayyōrĕdîm miṣrayim lĕʿezrâ</strong> = "Woe to those who go down to Egypt for help (<em>ʿezrâ</em>)" — parallel to 30:1-2 but now focused specifically on military hardware. <strong>ʿal-sûsîm yiššāʿēnû</strong> = "who rely on horses (<em>sûs</em>)" — Egyptian cavalry was the most prized military commodity in the ancient Near East (cf. Deut 17:16, where the king is forbidden to multiply horses). <strong>kî rāḇ meʾōd ḥêlô ʿāṣûm mĕʾōd pārāšāyw</strong> = "for their army is very large, their cavalry very strong" — the human logic of military alliance: numbers and cavalry = security. <strong>wĕlōʾ šāʿû ʿal-qĕdôš yiśrāʾēl wĕʾet-YHWH lōʾ dāraš û</strong> = "but they do not look to the Holy One of Israel, and they do not seek YHWH" — the structural failure: military calculation without theological consultation.</p>',
    "2": '<p><strong>wĕgam-hûʾ ḥāḵām wayyāḇēʾ rāʿ</strong> = "yet he too is wise and will bring disaster" — the sarcastic concession: YHWH is also "wise," but his wisdom produces judgment rather than deliverance for those who bypassed him. <strong>wĕlōʾ hēsîr dĕḇārāyw</strong> = "and he has not withdrawn his words" — YHWH\'s previous oracles of judgment remain in force; they are not canceled by the Egyptian alliance. <strong>wĕqām ʿal-bêt mĕrēʿîm wĕʿal-ʿezrat pōʿălê ʾāwen</strong> = "and he will rise against the house of evildoers and against the helpers of those who do iniquity." YHWH fights both against Israel (who sought the evil alliance) and against Egypt (who provided it).</p>',
    "3": '<p><strong>wĕmiṣrayim ʾādām wĕlōʾ-ʾēl wĕsûsêhem bāśār wĕlōʾ-rûaḥ</strong> = "Egypt is human (<em>ʾādām</em>) and not God (<em>ʾēl</em>), their horses are flesh (<em>bāśār</em>) and not spirit (<em>rûaḥ</em>)" — the decisive theological contrast: the alliance partners (Egypt, horses) are located entirely in the category of the creaturely (<em>ʾādām</em>, <em>bāśār</em>) rather than the divine (<em>ʾēl</em>, <em>rûaḥ</em>). The contrast is ontological, not merely pragmatic. <strong>wĕYHWH yiṭṭeh yādô wĕkāšal ʿōzēr wĕnāpāl ʿāzûr wĕyaḥdāw kullām yikleyû</strong> = "and when YHWH stretches out his hand, the helper will stumble and the helped will fall, and all of them will perish together" — both Egypt and Judah collapse together when YHWH acts. The alliance that was supposed to be saving proves mutually destructive.</p>',
    "4": '<p><strong>kî-kōh ʾāmar-lî YHWH kaʾăšer yehgeh hāʾaryēh wĕhakepir ʿal-ṭarpô</strong> = "For thus YHWH said to me: as the lion (<em>ʾaryēh</em>) growls (<em>hāgâ</em>) and the young lion (<em>kepir</em>) over his prey (<em>ṭerep</em>)" — YHWH is the lion standing over Jerusalem, not threatening it but protecting it. <strong>kî yiqqārēʾ ʿālāyw mĕlōʾ rōʿîm miqQôlam lōʾ yēḥāt</strong> = "when a multitude of shepherds is called out against him, he is not frightened (<em>ḥātat</em>) by their voice" — the lion is undaunted by the noise of human armies. YHWH as lion = both protector of Jerusalem (positive) and threat to enemies.</p>',
    "5": '<p><strong>kĕṣipporîm ʿāpôt kēn yāgēn YHWH ṣĕḇāʾôt ʿal-yĕrûšālaim</strong> = "Like hovering birds (<em>ṣipporîm ʿāpôt</em>), so YHWH of hosts will protect (<em>gānan</em>) Jerusalem" — two incompatible images in consecutive verses: lion (v4) and hovering birds (v5). The lion = fierce protection; the birds = delicate, attentive protection (cf. Deut 32:11: the eagle hovering over its young). Together they describe divine protection that is both powerful and tender. <strong>gānôn wĕhiṣṣîl pāsôaḥ wĕhimliṭ</strong> = "protecting and delivering, sparing and rescuing" — four verbs of deliverance paired asyndetically, creating urgency and comprehensiveness.</p>',
    "6": '<p><strong>šûḇû lĕʾăšer heeʿemîqû sārâ bĕnê yiśrāʾēl</strong> = "Return (<em>šûḇ</em>) to the one from whom they have deeply revolted (<em>heeʿămîqû sārâ</em>)" — the call to repentance in the middle of the judgment-oracle. <em>Heeʿămîqû</em> = they have gone deep in revolt (the word of depth applied to their apostasy). The lion who protects is also the one from whom they fled; returning (<em>šûḇ</em>) to the protector is the only path to safety.</p>',
    "7": '<p><strong>kî bĕyôm hahûʾ yimʾăsûn ʾîš ʾĕlîlêyw kesep wĕʾĕlîlêyw zāhāḇ</strong> = "For in that day everyone will reject (<em>māʾas</em>) his silver idols and golden idols" — the repentance expressed in concrete terms: abandonment of material religion. <strong>ʾăšer ʿāśû lākem yĕdêkem ḥēṭĕʾ</strong> = "which your own hands have made for you, sinfully" — the idols are the work of human hands (<em>yĕdêkem</em>), not the work of God; the distinction of 31:3 (human vs. divine, <em>ʾādām</em> vs. <em>ʾēl</em>) is applied to worship objects as well as military allies.</p>',
    "8": '<p><strong>wĕnāpal ʾAššûr bĕḥereḇ lōʾ-ʾîš wĕḥereḇ lōʾ-ʾādām tōʾklennû</strong> = "And Assyria will fall by the sword, but not of man (<em>ʾîš</em>); a sword, but not of man (<em>ʾādām</em>), will devour him" — the double negation is crucial: Assyria\'s defeat will not come through Egyptian cavalry or human military power (the very thing Judah sought) but through direct divine action. <strong>wĕnās mippĕnê-ḥāreḇ ûbaḥûrāyw lāmas yihyû</strong> = "and he will flee from the sword and his young men will become forced labor (<em>mas</em>)" — the military elite that was Assyria\'s pride reduced to corvée workers.</p>',
    "9": '<p><strong>wĕsalʿô mimmāgôr yaʿăḇōr</strong> = "and his rock (<em>sela</em>) will pass away in terror (<em>māgôr</em>)" — Assyria\'s stronghold (either a deity or military fortress) will crumble in fear. <strong>wĕḥaṭṭāʾû ʾet-nisSô miyyîrāʾ</strong> = "and his officers will be terrified at the battle standard" — the commanders who rallied troops to the standard (<em>nēs</em>) will flee from it. <strong>nĕʾum YHWH ʾăšer-ûr lô bĕṣiyyôn wĕtannûr lô bîrûšālaim</strong> = "declares YHWH, whose fire (<em>ʾûr</em>) is in Zion and whose furnace (<em>tannûr</em>) is in Jerusalem" — the closing declaration: the fire of divine judgment is located in Zion. It destroys the enemy (Assyria) while purifying the city (Jerusalem).</p>'
  },
  "32": {
    "1": '<p><strong>hēn lĕṣedeq yimlōk melek</strong> = "Behold, a king (<em>melek</em>) will reign (<em>mālaḵ</em>) in righteousness (<em>ṣedeq</em>)" — the messianic-political ideal: a king who is characterized by <em>ṣedeq</em> (righteousness = conformity to divine standard of justice). <strong>wĕlĕmišpāṭ śārîm yāśōrû</strong> = "and princes will rule (<em>śārar</em>) in justice (<em>mišpāṭ</em>)." The pairing <em>ṣedeq</em>/<em>mišpāṭ</em> = the twin pillars of the restored kingdom (cf. 1:26-27; 9:7; 11:4-5; 33:5). The righteous king anticipates the Davidic Messiah who will embody both.</p>',
    "2": '<p><strong>wĕhāyâ hāʾîš kĕmastēr-rûaḥ ûmahseh zerem</strong> = "And that man will be like a shelter from the wind (<em>rûaḥ</em>) and a refuge from the rainstorm (<em>zerem</em>)" — four natural refuge images: shelter from wind, shelter from storm, streams of water in a dry place, shadow of a great rock in a parched land. Each describes the protective function of the righteous king for the vulnerable. The rock in a weary land recalls the water-from-the-rock of the wilderness (Exod 17; Num 20) and anticipates Paul\'s identification of that rock as Christ (1 Cor 10:4). <strong>kĕpalgê-mayim bĕṣāyôn kĕṣēl sela kāḇēd bĕʾereṣ ʿāyēpâ</strong> = "like streams of water in a dry place, like the shadow of a great rock in a weary land."</p>',
    "3": '<p><strong>wĕlōʾ tišʿênâ ʿênê rōʾîm</strong> = "and the eyes of those who see will not be closed (<em>šāʿâ</em>)" — the reversal of the hardening commission of 6:9-10 (where eyes were blinded and ears made heavy). In the kingdom of the righteous king, the perceptual faculties that were sealed in judgment are reopened. <strong>wĕʾoznê šōmĕʿîm tiqšābnâ</strong> = "and the ears of those who hear will pay attention (<em>qāšaḇ</em>)" — <em>qāšaḇ</em> = to incline toward, to attend carefully. The attentiveness that Israel refused (1:2; 28:23) will characterize the restored community.</p>',
    "4": '<p><strong>wĕlēḇāḇ mahîrîm yāḇîn lādaʿat</strong> = "and the heart of the hasty (<em>mahîrîm</em>) will understand to know (<em>yāḇîn lādaʿat</em>)" — those who were rash in judgment will gain measured understanding. <strong>ûlĕšôn ʿilgîm tĕmahēr lĕdabbēr ṣāḥôt</strong> = "and the tongue of the stammerers (<em>ʿilgîm</em>) will speak clearly (<em>ṣāḥôt</em>)" — the stammerer whose speech was unclear will speak plainly and readily. All four verses (vv3-4) describe the restoration of communicative capacity — seeing, hearing, understanding, speaking — in the kingdom of the righteous king.</p>',
    "5": '<p><strong>lōʾ-yiqqārēʾ ʿôd lĕnāḇāl nāḏîḇ</strong> = "the fool (<em>nāḇāl</em>) will no longer be called noble (<em>nāḏîḇ</em>)" — the social reversal of titles: the morally bankrupt person who held elite status will no longer be honored. <strong>ûlĕkilay lōʾ yēʾāmer šôaʿ</strong> = "and the deceiver (<em>kilay</em>) will not be called generous (<em>šôaʿ</em>)" — the exploitation labeled as generosity will be exposed. The righteous king\'s reign brings truth in naming: people will be called what they are, not what they have fraudulently claimed.</p>',
    "6": '<p><strong>kî nāḇāl nĕḇālâ yĕdabbēr</strong> = "for the fool speaks folly (<em>nĕḇālâ</em>)" — <em>nāḇāl</em> (H5036) = the fool as a moral category (cf. Ps 14:1: "the fool says in his heart, there is no God"), not merely an intellectual classification. <strong>wĕlibbô yaʿăśeh-ʾāwen lĕʿăśôt ḥānēp</strong> = "and his heart practices iniquity (<em>ʾāwen</em>), to practice godlessness (<em>ḥānep</em>)." <strong>wĕdabbēr ʾel-YHWH tôʿâ</strong> = "and he speaks error concerning YHWH" — theological confusion at the root of social evil. <strong>lĕhārēq nepeš rāʿēḇ</strong> = "to leave the hungry soul (<em>nepeš</em>) empty" — the practical consequence of foolishness: the hungry go unfed. The fool\'s theological error produces social neglect.</p>',
    "7": '<p><strong>wĕkilay kĕlāyw rāʿîm</strong> = "and the deceiver — his weapons (<em>kĕlîm</em>) are evil" — <em>kĕlîm</em> literally = implements/weapons; the deceiver\'s instruments of action are evil from the start. <strong>hûʾ zim-môt yaʿaṣ lĕḥabbēl ʿănāwîm bĕʾimrê-šāqer</strong> = "he devises wicked schemes to ruin the poor (<em>ʿănāwîm</em>) with false words (<em>ʾimrê-šāqer</em>)" — the target of the deceiver\'s evil is consistently the vulnerable (<em>ʿănāwîm</em>, the lowly/poor). <strong>wĕʾeḇyôn bĕdabbēr mišpāṭ</strong> = "and the needy (<em>ʾeḇyôn</em>) when he speaks what is right" — the needy person seeking legal justice is the particular victim of the deceiver\'s false words.</p>',
    "8": '<p><strong>wĕnāḏîḇ nĕḏîḇôt yaʿăṣ wĕhûʾ ʿal-nĕḏîḇôt yāqûm</strong> = "but the noble person (<em>nāḏîḇ</em>) devises noble things (<em>nĕḏîḇôt</em>), and by noble things he stands." The contrast to the fool (vv6-7) and the deceiver: the truly noble person is characterized by noble intentions that match their noble status. <em>Nāḏîḇ</em> in the restored kingdom means what it should mean: those with elevated status use it for elevated purposes, not for personal enrichment at the expense of the poor.</p>',
    "9": '<p><strong>šaʾănannôt bānôt šimʿû qôlî bānôt bôṭĕḥôt haʾăzinnâ ʾimrātî</strong> = "Rise up, you women who are at ease (<em>šaʾănannôt</em>), hear my voice; you complacent daughters, listen to my speech" — the address to women of leisure echoes 3:16-4:1 (the indictment of the daughters of Zion). Here the complacent women represent the ease of those who assume security without righteousness. The prophetic address to women signals a particular social class: those insulated from the consequences of political decisions by wealth.</p>',
    "10": '<p><strong>yāmîm ʿal-šānâ tirgazânâ bôṭĕḥôt</strong> = "within a year and some days (<em>yāmîm ʿal-šānâ</em>), you will be in anguish, complacent ones" — a specific time indicator, unusual in prophetic oracles: the complacency will be shattered within a year. <strong>kî-kālâ bāṣîr ʾāsip bĕlî yāḇôʾ</strong> = "for the vintage (<em>bāṣîr</em>) will fail, the harvest (<em>ʾāsip</em>) will not come" — the agricultural metaphor for the economic collapse that will follow Assyrian invasion. The women\'s comfortable life depends on agricultural abundance that is about to end.</p>',
    "11": '<p><strong>ḥirĕdû šaʾănannôt rĕgāzû bôṭĕḥôt</strong> = "Tremble, you women who are at ease; quake, complacent ones" — the reversal: the at-ease women will tremble (<em>ḥārad</em>), the self-secure will quake (<em>rāgaz</em>). <strong>Pitšĕṭû wĕʿôr ûḥigîrû ʿal-ḥălāṣāyim</strong> = "strip yourselves bare and put on sackcloth (<em>śaq</em>) on your loins" — the movement from fine clothing (3:16-24) to sackcloth is the outward sign of mourning, the reversal of the adornments described in 3:18-23.</p>',
    "12": '<p><strong>ʿal-šādayim sōpĕdîm</strong> = "beat your breasts (<em>šādayim</em>)" — the gesture of grief: beating the chest is the universal mourning posture in the ancient Near East (cf. Luke 18:13 where the tax collector beats his breast; Luke 23:48 where crowds beat their breasts after the crucifixion). <strong>ʿal śĕdê ḥemdâ ʿal-gepen pōriyyâ</strong> = "for the pleasant fields, for the fruitful vine" — the mourning is specifically over lost agricultural abundance: the good land destroyed by invasion.</p>',
    "13": '<p><strong>ʿal ʾadmat ʿammî qôṣ šāmîr taʿăleh</strong> = "Over the soil (<em>ʾadmâ</em>) of my people thorns (<em>qôṣ</em>) and briars (<em>šāmîr</em>) shall come up" — the <em>šāmîr wāšît</em> pair (5:6; 7:23-25) signals the curse-reversal of the land; the cultivated soil returns to wilderness. <strong>kî ʿal-kol-bāttê māśôś qiryat ʿallîzâ</strong> = "over all the joyful houses in the exultant city" — Jerusalem, characterized by festive houses and joyful celebration, will become a desolation of thorns.</p>',
    "14": '<p><strong>kî-ʾarmon nuṭṭāš hāmôn ʿîr ʿuzZāḇ</strong> = "for the palace (<em>ʾarmôn</em>) will be forsaken (<em>nāṭaš</em>), the noisy city (<em>hāmôn ʿîr</em>) abandoned (<em>ʿāzaḇ</em>)" — the architectural symbols of urban civilization — palace and city — emptied. <strong>ʿōpel ûḇaḥan hāyû bĕʿad mĕʿārâ ʿad-ʿôlām</strong> = "the hill and the watchtower will become dens (<em>mĕʿārâ</em>) forever (<em>ʿad-ʿôlām</em>)" — permanent reversal: the defensive infrastructure becomes animal shelter. <strong>śimḥat pĕrāʾîm</strong> = "the delight of wild donkeys" — the city that was a delight to humans becomes a pasture for feral animals.</p>',
    "15": '<p><strong>ʿad-yiqqāreh ʿālênû rûaḥ mimārome</strong> = "until the Spirit (<em>rûaḥ</em>) is poured upon us from on high (<em>mimārome</em>)" — the great turning point: the Spirit poured from above. <em>Yiqqāreh</em> (niphal of <em>ʿārâ</em>) = to be poured out. This is one of the great OT Spirit-promise texts: the Spirit poured from heaven transforming the earth (cf. Ezek 36:26-27; 37:14; Joel 2:28-29). <strong>wĕhāyâ midbar lakarmel wĕhakarmel layaʿar yeḥāšēḇ</strong> = "and the wilderness becomes a fruitful field (<em>karmel</em>) and the fruitful field is regarded as a forest." The outpouring of the Spirit produces the agricultural reversal: desert → garden → forest. Acts 2 (the Spirit poured at Pentecost) is the initial fulfillment; the consummation remains eschatological.</p>',
    "16": '<p><strong>wĕšākan bammidbar mišpāṭ</strong> = "then justice (<em>mišpāṭ</em>) will dwell (<em>šākan</em>) in the wilderness" — <em>šākan</em> = to tabernacle, dwell as a resident; the same root as the Mishkan (tabernacle) and the divine dwelling. Justice tabernacles in what was previously wilderness — the Spirit\'s transforming work is both ecological and social. <strong>ûṣĕdāqâ bakkarmel tēšēḇ</strong> = "and righteousness (<em>ṣĕdāqâ</em>) will abide (<em>yāšaḇ</em>) in the fruitful field." Both pillars of the ideal kingdom (v1: <em>ṣedeq/mišpāṭ</em>) are now embedded in the transformed landscape: the Spirit-created ecology is also the Spirit-created social order.</p>',
    "17": '<p><strong>wĕhāyâ maʿăśēh haṣṣĕdāqâ šālôm</strong> = "and the work (<em>maʿăśeh</em>) of righteousness will be peace (<em>šālôm</em>)" — righteousness produces peace as its necessary fruit. <strong>waʿăḇōdat haṣṣĕdāqâ hašqēṭ ûḇeṭaḥ ʿad-ʿôlām</strong> = "and the service of righteousness will be quietness and trust (<em>beṭaḥ</em>) forever." <em>Hašqēṭ ûḇeṭaḥ</em> echoes 30:15 ("in quietness and trust is your strength") — the faith-rest that Israel refused becomes the permanent condition of the restored community under the Spirit. Peace as the fruit of righteousness, not its precondition.</p>',
    "18": '<p><strong>wĕyāšaḇ ʿammî bĕnĕwēh šālôm</strong> = "and my people will dwell in a peaceful habitation (<em>nĕwēh šālôm</em>)" — <em>nĕwēh</em> = pasture, home, settled dwelling place; the image of the flock in its safe pasture applied to the human community. <strong>ûḇĕmiškĕnôt miṭṭāḥôt</strong> = "and in secure dwellings (<em>miškĕnôt miṭṭāḥôt</em>)" — <em>miškān</em> (tabernacle-root) = dwelling place; <em>miṭṭāḥ</em> = spreading out, relaxed security. <strong>ûḇimnûḥôt šaʾănannôt</strong> = "and in quiet resting places" — the three terms stack up into a comprehensive image of shalom: peaceful place, secure dwelling, quiet rest. The "complacent women" (vv9-12) will have true security rather than false security.</p>',
    "19": '<p><strong>ûbārad bĕredet hāyāʿar</strong> = "and hail will fall (<em>bārad</em>) when the forest is brought low" — the judgment on the proud (the forest as symbol of arrogant power, cf. 10:18-19; 29:17) comes through hail, a weapon of theophanic warfare (cf. 30:30). <strong>ûšiplâ hāʿîr tišpāl</strong> = "and the city (<em>hāʿîr</em>) will be utterly humbled (<em>šāpēl</em>)" — the city of human pride is brought low by divine hail. The verse interrupts the peace-oracle (vv15-18) with a reminder: the shalom follows judgment, not instead of it.</p>',
    "20": '<p><strong>ʾašrêkem zorĕʿê ʿal-kol-māyim</strong> = "Blessed (<em>ʾašrê</em>) are you who sow beside all waters" — the final beatitude of the chapter: those who farm the Spirit-watered land are blessed. <strong>mĕšallĕḥê regel-hašŝôr wĕhaḥămôr</strong> = "who let the feet of the ox and donkey roam free" — the animals graze freely in the restored land. The chapter that began with the righteous king (v1) ends with the blessed farmer: the kingdom of righteousness produces not only justice in the courts but abundance in the fields. The Spirit poured from above (v15) results in land, livestock, and human flourishing.</p>'
  }
}

def main():
    data = load_comm('mkt-original', 'isaiah')
    before = sum(len(v) for v in data.values())
    merge_comm(data, ISAIAH)
    save_comm('mkt-original', 'isaiah', data)
    after = sum(len(v) for v in data.values())
    print(f'  verses: {before} → {after} (+{after - before})')

if __name__ == '__main__':
    main()
